12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Step = QuoteStep;
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const itemBasePremium = (item: Item): number => ITEM_BASE_PREMIUM[item.type];
18	
19	const quotePremium = (items: Item[]): number => {
20	  const basePremium = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
21	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
22	  return Math.ceil(basePremium + firstInsuranceSurcharge) + PROCESSING_FEE;
23	};
24	
25	const runStep = (step: Step) => ({ premium: quotePremium(step.items) });
26	
27	export const runScenario = (scenario: Scenario): unknown => ({
28	  results: scenario.steps.map(runStep),
29	});
